CREATE TYPE "FleetAssetType" AS ENUM ('Truck', 'Trailer', 'Equipment');
CREATE TYPE "FleetAssetStatus" AS ENUM ('Active', 'Maintenance', 'OutOfService', 'Retired');
CREATE TYPE "DisposalCategory" AS ENUM ('Landfill', 'Donation', 'Recycling', 'ScrapMetal', 'HazardousWaste');
CREATE TYPE "TimeEntryType" AS ENUM ('Work', 'PTO');
ALTER TABLE "employees" ADD COLUMN "availability" TEXT, ADD COLUMN "certifications" TEXT[] NOT NULL DEFAULT ARRAY[]::TEXT[], ADD COLUMN "assignedTruckId" TEXT;
ALTER TABLE "jobs" ADD COLUMN "assignedFleetAssetId" TEXT;
CREATE TABLE "fleet_assets" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"type" "FleetAssetType" NOT NULL,"name" TEXT NOT NULL,"status" "FleetAssetStatus" NOT NULL DEFAULT 'Active',"vin" TEXT,"licensePlate" TEXT,"insuranceExpiresAt" TIMESTAMP(3),"registrationExpiresAt" TIMESTAMP(3),"odometer" INTEGER,"oilChangeDueAt" INTEGER,"tireServiceDueAt" INTEGER,"notes" TEXT NOT NULL DEFAULT '',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "fleet_assets_pkey" PRIMARY KEY ("id"),CONSTRAINT "fleet_assets_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "companies"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "fleet_maintenance" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"assetId" TEXT NOT NULL,"serviceType" TEXT NOT NULL,"servicedAt" TIMESTAMP(3) NOT NULL,"mileage" INTEGER,"cost" DOUBLE PRECISION NOT NULL DEFAULT 0,"nextDueAt" TIMESTAMP(3),"nextDueMileage" INTEGER,"notes" TEXT NOT NULL DEFAULT '',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "fleet_maintenance_pkey" PRIMARY KEY ("id"),CONSTRAINT "fleet_maintenance_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "companies"("id") ON DELETE CASCADE ON UPDATE CASCADE,CONSTRAINT "fleet_maintenance_assetId_fkey" FOREIGN KEY ("assetId") REFERENCES "fleet_assets"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "disposal_records" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"jobId" TEXT NOT NULL,"category" "DisposalCategory" NOT NULL,"facility" TEXT NOT NULL,"cost" DOUBLE PRECISION NOT NULL DEFAULT 0,"weight" DOUBLE PRECISION,"receiptUrl" TEXT,"notes" TEXT NOT NULL DEFAULT '',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "disposal_records_pkey" PRIMARY KEY ("id"),CONSTRAINT "disposal_records_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "companies"("id") ON DELETE CASCADE ON UPDATE CASCADE,CONSTRAINT "disposal_records_jobId_fkey" FOREIGN KEY ("jobId") REFERENCES "jobs"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE TABLE "employee_time_entries" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"employeeId" TEXT NOT NULL,"type" "TimeEntryType" NOT NULL DEFAULT 'Work',"clockIn" TIMESTAMP(3) NOT NULL,"clockOut" TIMESTAMP(3),"notes" TEXT NOT NULL DEFAULT '',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "employee_time_entries_pkey" PRIMARY KEY ("id"),CONSTRAINT "employee_time_entries_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "companies"("id") ON DELETE CASCADE ON UPDATE CASCADE,CONSTRAINT "employee_time_entries_employeeId_fkey" FOREIGN KEY ("employeeId") REFERENCES "employees"("id") ON DELETE CASCADE ON UPDATE CASCADE);
ALTER TABLE "employees" ADD CONSTRAINT "employees_assignedTruckId_fkey" FOREIGN KEY ("assignedTruckId") REFERENCES "fleet_assets"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "jobs" ADD CONSTRAINT "jobs_assignedFleetAssetId_fkey" FOREIGN KEY ("assignedFleetAssetId") REFERENCES "fleet_assets"("id") ON DELETE SET NULL ON UPDATE CASCADE;
CREATE INDEX "fleet_assets_companyId_status_idx" ON "fleet_assets"("companyId","status");
CREATE INDEX "fleet_maintenance_companyId_nextDueAt_idx" ON "fleet_maintenance"("companyId","nextDueAt");
CREATE INDEX "disposal_records_companyId_jobId_idx" ON "disposal_records"("companyId","jobId");
CREATE INDEX "employee_time_entries_companyId_employeeId_clockIn_idx" ON "employee_time_entries"("companyId","employeeId","clockIn");
